// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Differential tests for intra-query morsel parallelism on native COUNT aggregation: queries are evaluated three ways —
 * native with parallel execution enabled, sequential native ({@code rdf4j.lmdb.parallel.enabled=false}), and the
 * generic evaluator ({@code rdf4j.lmdb.nativeQueryEngine.enabled=false}) — and all results must match. Single-pattern
 * aggregation also proves that the order-preserving parallel path still engages. The star dataset includes a hub with a
 * zero-match branch, duplicate values across hubs, and a named-graph triple.
 */
public class LmdbNativeParallelAggregationTest {

	private static final String EX = "http://example.com/";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final String PARALLEL_FLAG = "rdf4j.lmdb.parallel.enabled";
	private static final String THRESHOLD_FLAG = "rdf4j.lmdb.parallel.minRootEstimate";
	private static final String THREADS_FLAG = "rdf4j.lmdb.parallel.threads";
	private static final String MAX_TASKS_FLAG = "rdf4j.lmdb.parallel.maxTasks";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		System.setProperty(THRESHOLD_FLAG, "0");
		System.setProperty(THREADS_FLAG, "4");
		System.setProperty(MAX_TASKS_FLAG, "4");
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			conn.begin();
			for (int hub = 0; hub < 50; hub++) {
				IRI subject = vf.createIRI(EX, "hub" + hub);
				for (int i = 0; i < 4; i++) {
					conn.add(subject, p1, vf.createIRI(EX, "a" + ((hub * 4 + i) % 60)));
				}
				// hub49 has no p2 branch and must vanish from joined aggregates
				if (hub != 49) {
					for (int i = 0; i < 6; i++) {
						conn.add(subject, p2, vf.createIRI(EX, "b" + ((hub * 6 + i) % 40)));
					}
				}
			}
			conn.add(vf.createIRI(EX, "hub0"), p2, vf.createIRI(EX, "bGraph"), vf.createIRI(EX, "g1"));
			// numeric branch for value-typed aggregates: exact arithmetic only (integers and decimals),
			// so the parallel merge order cannot perturb SUM/AVG results
			IRI p3 = vf.createIRI(EX, "p3");
			for (int hub = 0; hub < 50; hub++) {
				IRI subject = vf.createIRI(EX, "hub" + hub);
				for (int i = 0; i < 5; i++) {
					conn.add(subject, p3, vf.createLiteral(hub * 7 + i * 3 - 20));
				}
				conn.add(subject, p3, vf.createLiteral(new java.math.BigDecimal(hub + ".25")));
			}
			conn.commit();
		}
	}

	@AfterEach
	public void tearDown() {
		System.clearProperty(THRESHOLD_FLAG);
		System.clearProperty(THREADS_FLAG);
		System.clearProperty(MAX_TASKS_FLAG);
		repository.shutDown();
	}

	private List<String> rows(String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			return result.stream()
					.map(bs -> bs.getBindingNames()
							.stream()
							.sorted()
							.map(name -> name + "=" + bs.getValue(name))
							.collect(Collectors.joining(";", "[", "]")))
					.sorted()
					.collect(Collectors.toList());
		}
	}

	private List<String> rowsWithProperty(String property, String value, String query) {
		String previous = System.getProperty(property);
		try {
			System.setProperty(property, value);
			return rows(query);
		} finally {
			if (previous == null) {
				System.clearProperty(property);
			} else {
				System.setProperty(property, previous);
			}
		}
	}

	private void assertAllThreeAgree(String query) {
		List<String> parallelRows = rows(query);
		List<String> sequentialRows = rowsWithProperty(PARALLEL_FLAG, "false", query);
		List<String> genericRows = rowsWithProperty(NATIVE_FLAG, "false", query);
		assertThat(parallelRows).as("parallel-enabled vs sequential native for:\n" + query).isEqualTo(sequentialRows);
		assertThat(parallelRows).as("parallel-enabled vs generic for:\n" + query).isEqualTo(genericRows);
	}

	private void assertParallelEngagesAndAllThreeAgree(String query) {
		long before = LmdbNativeParallelAggregation.PARALLEL_RUNS.get();
		List<String> parallelRows = rows(query);
		assertThat(LmdbNativeParallelAggregation.PARALLEL_RUNS.get())
				.as("parallel path should engage for:\n" + query)
				.isGreaterThan(before);
		List<String> sequentialRows = rowsWithProperty(PARALLEL_FLAG, "false", query);
		List<String> genericRows = rowsWithProperty(NATIVE_FLAG, "false", query);
		assertThat(parallelRows).as("parallel vs sequential native for:\n" + query).isEqualTo(sequentialRows);
		assertThat(parallelRows).as("parallel vs generic for:\n" + query).isEqualTo(genericRows);
	}

	private static String star(String select, String extra) {
		return "PREFIX ex: <" + EX + ">\n"
				+ "SELECT " + select + " WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ extra
				+ "}";
	}

	@Test
	public void plainCount() {
		assertAllThreeAgree(star("(COUNT(?s) AS ?c)", ""));
	}

	@Test
	public void countDistinctHubAndTail() {
		assertAllThreeAgree(star("(COUNT(DISTINCT ?s) AS ?c) (COUNT(DISTINCT ?b) AS ?d)", ""));
	}

	@Test
	public void mixedPlainAndDistinctCounts() {
		assertAllThreeAgree(star("(COUNT(?b) AS ?c) (COUNT(DISTINCT ?a) AS ?d) (COUNT(?a) AS ?e)", ""));
	}

	@Test
	public void groupBySingleSlot() {
		assertAllThreeAgree(star("?s (COUNT(?b) AS ?c) (COUNT(DISTINCT ?b) AS ?d)", "") + " GROUP BY ?s");
	}

	@Test
	public void groupByTailSlot() {
		assertAllThreeAgree(star("?b (COUNT(?s) AS ?c)", "") + " GROUP BY ?b");
	}

	@Test
	public void groupByTwoSlots() {
		assertAllThreeAgree(star("?s ?a (COUNT(?b) AS ?c)", "") + " GROUP BY ?s ?a");
	}

	@Test
	public void singlePatternPlainCountUsesParallelAggregation() {
		assertParallelEngagesAndAllThreeAgree("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) WHERE { ?s ex:p1 ?a . }");
	}

	@Test
	public void singlePatternDistinctPrefersMonotonicAggregation() {
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) (COUNT(DISTINCT ?a) AS ?d) WHERE { ?s ex:p1 ?a . }";
		try (SailRepositoryConnection connection = repository.getConnection()) {
			assertThat(connection.prepareTupleQuery(query).explain(Explanation.Level.Optimized).toString())
					.contains("distinctChannels=[MONOTONIC]");
		}
		long before = LmdbNativeParallelAggregation.PARALLEL_RUNS.get();
		assertAllThreeAgree(query);
		assertThat(LmdbNativeParallelAggregation.PARALLEL_RUNS.get())
				.as("an exact order that removes the DISTINCT hash must run before parallel aggregation")
				.isEqualTo(before);
	}

	@Test
	public void factorizedDistinctStarKeepsParallelAggregation() {
		String query = star("(COUNT(DISTINCT ?b) AS ?d)", "");
		long before = LmdbNativeParallelAggregation.PARALLEL_RUNS.get();
		rows(query);
		assertThat(LmdbNativeParallelAggregation.PARALLEL_RUNS.get())
				.as("a multiply-factorized multi-join must not be replaced by a sequential ordered scan")
				.isGreaterThan(before);
	}

	@Test
	public void namedGraphPattern() {
		assertAllThreeAgree("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?b) AS ?c) WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  GRAPH ?g { ?s ex:p2 ?b . }\n"
				+ "}");
	}

	@Test
	public void chainedPatterns() {
		assertAllThreeAgree("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) (COUNT(DISTINCT ?b) AS ?d) WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ "  ?s ex:p1 ?a2 .\n"
				+ "}");
	}

	@Test
	public void filteredQueryStaysSequentialButCorrect() {
		String query = star("(COUNT(?s) AS ?c)", "  FILTER(?b != ex:b1)\n");
		long before = LmdbNativeParallelAggregation.PARALLEL_RUNS.get();
		List<String> nativeRows = rows(query);
		assertThat(LmdbNativeParallelAggregation.PARALLEL_RUNS.get())
				.as("compiled filters are not thread-safe to share; the gate must hold")
				.isEqualTo(before);
		assertThat(nativeRows).isEqualTo(rowsWithProperty(NATIVE_FLAG, "false", query));
	}

	@Test
	public void defaultThresholdGatesSmallStores() {
		String previous = System.getProperty(THRESHOLD_FLAG);
		try {
			System.clearProperty(THRESHOLD_FLAG);
			long before = LmdbNativeParallelAggregation.PARALLEL_RUNS.get();
			rows(star("(COUNT(?s) AS ?c)", ""));
			assertThat(LmdbNativeParallelAggregation.PARALLEL_RUNS.get())
					.as("a few hundred root rows are far below the default 50k threshold")
					.isEqualTo(before);
		} finally {
			if (previous != null) {
				System.setProperty(THRESHOLD_FLAG, previous);
			}
		}
	}

	@Test
	public void valueAggregatesRunParallel() {
		// Phase 6: SUM/AVG/MIN/MAX merge exactly across workers, so the COUNT-only gate is gone
		assertParallelEngagesAndAllThreeAgree(starWithValues(
				"?s (SUM(?v) AS ?sum) (AVG(?v) AS ?avg) (MIN(?v) AS ?min) (MAX(?v) AS ?max)") + " GROUP BY ?s");
	}

	@Test
	public void valueAggregatesWithoutGroupingRunParallel() {
		assertParallelEngagesAndAllThreeAgree(starWithValues("(SUM(?v) AS ?sum) (MAX(?v) AS ?max)"));
	}

	@Test
	public void distinctValueAggregateStaysSequentialButCorrect() {
		String query = starWithValues("(SUM(DISTINCT ?v) AS ?sum)");
		long before = LmdbNativeParallelAggregation.PARALLEL_RUNS.get();
		List<String> nativeRows = rows(query);
		assertThat(LmdbNativeParallelAggregation.PARALLEL_RUNS.get())
				.as("per-worker distinct-then-accumulate cannot merge without double counting: the gate must hold")
				.isEqualTo(before);
		assertThat(nativeRows).isEqualTo(rowsWithProperty(NATIVE_FLAG, "false", query));
	}

	private static String starWithValues(String select) {
		return "PREFIX ex: <" + EX + ">\n"
				+ "SELECT " + select + " WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p3 ?v .\n"
				+ "}";
	}

	@Test
	public void emptyJoinStillProducesZeroCount() {
		// the unknown predicate folds the plan to EmptyPlan at compile time, so this stays sequential;
		// only result equality is asserted
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) WHERE { ?s ex:p1 ?a . ?s ex:missing ?m . }";
		assertThat(rows(query)).isEqualTo(rowsWithProperty(NATIVE_FLAG, "false", query));
	}
}
